def prob_T(weights,p,c,alpha,beta):
    n=len(weights); A=D=0
    for mask in range(1<<n):
        s=0; prob=1
        for i,w in enumerate(weights):
            if mask>>i&1:
                s+=w; prob*=p
            else:
                prob*=1-p
        if s >= p-beta -1e-12: A+=prob
        if s < p-alpha -1e-12: D+=prob
    return A,D

def rand_weights(total,n):
    if n==0: return []
    xs=[random.expovariate(1) for _ in range(n)]
    s=sum(xs)
    return [total*x/s for x in xs]
