    for mask in range(1<<n):
        s=0; prob=1
        for i,w in enumerate(weights):
            if mask>>i&1:
                s+=w; prob*=p
            else:
                prob*=1-p
        if s >= p - 1e-12: U += prob
        if s < p-a - 1e-12: L += prob
    return U,L
