def prob_R(weights,p,a,b):
    n=len(weights); A=E=C=0
    c=a+b
    for mask in range(1<<n):
        s=0; prob=1
        for i,w in enumerate(weights):
            if mask>>i&1:
                s+=w; prob*=p
            else:
                prob*=1-p
        if s >= p-b -1e-12: A += prob
        if s < p-c -1e-12: C += prob
        if s >= p-c -1e-12 and s < p-a -1e-12: E += prob
    return A,E,C
