def find_pair_merge_nonincrease(weights,p,a,eps=1e-12):
    base=phi(weights,p,a)
    n=len(weights)
    for i in range(n):
        for j in range(i+1,n):
            merged=[weights[k] for k in range(n) if k not in (i,j)] + [weights[i]+weights[j]]
            if phi(merged,p,a) <= base+1e-9:
                return (i,j,phi(merged,p,a),base)
    return None
